const crypto = require('crypto');

function hashPassword(password) {
  return new Promise((resolve, reject) => {
    crypto.createHmac('sha256', password)
      .update(password)
      .digest('base64')
      .then(hashedPassword => resolve(hashedPassword))
      .catch(err => reject(err));
  });
}